#!/usr/bin/env python3 """ Enhanced RFT v2 with length header, per-message salt, and HMAC tag. Provides IND-CPA security and integrity protection while keeping the Feistel core untouched. """ import enhanced_rft_crypto import struct import secrets import hmac import hashlib import time from typing import Tuple MAGIC = b"R2" # format marker VER = 1 # version byte SALT_SZ = 16 TAG_SZ = 16 # truncated HMAC-SHA256 def hkdf_extract(salt: bytes, ikm: bytes) -> bytes: """HKDF Extract step: PRK = HMAC-Hash(salt, IKM)""" return hmac.new(salt, ikm, hashlib.sha256).digest() def hkdf_expand(prk: bytes, info: bytes, length: int) -> bytes: """HKDF Expand step: OKM = T(1) | T(2) | ... | T(N)""" okm = b"" T = b"" c = 1 while len(okm) < length: T = hmac.new(prk, T + info + bytes([c]), hashlib.sha256).digest() okm += T c += 1 return okm[:length] def derive_keys(master_key: bytes, salt: bytes) -> Tuple[bytes, bytes]: """Derive encryption and MAC keys from master key using HKDF-SHA256""" prk = hkdf_extract(salt, master_key) okm = hkdf_expand(prk, b"ENHANCED_RFT_V2", 64) return okm[:32], okm[32:] # enc_key, mac_key class FixedRFTCryptoV2: """Enhanced RFT v2 with length header, per-message salt, and HMAC tag.""" def __init__(self): self.engine = enhanced_rft_crypto.PyEnhancedRFTCrypto() def encrypt(self, plaintext: bytes, key: bytes) -> bytes: """Encrypt with IND-CPA security and integrity protection.""" original_len = len(plaintext) # Feistel wants even length → pad by 1 zero if odd if (original_len & 1) == 1: plaintext += b"\x00" # Generate random salt for this message salt = secrets.token_bytes(SALT_SZ) enc_key, mac_key = derive_keys(key, salt) # Encrypt with derived key ct = self.engine.encrypt(plaintext, enc_key) # Build authenticated header header = MAGIC + bytes([VER]) + salt + struct.pack("<I", original_len) # Generate HMAC tag over header + ciphertext tag = hmac.new(mac_key, header + ct, hashlib.sha256).digest()[:TAG_SZ] return header + ct + tag def decrypt(self, blob: bytes, key: bytes) -> bytes: """Decrypt with authentication verification.""" # Parse and validate header min_size = 2 + 1 + SALT_SZ + 4 + TAG_SZ # magic + ver + salt + len + tag if len(blob) < min_size: raise ValueError("ciphertext too short") if blob[:2] != MAGIC: raise ValueError("bad magic") ver = blob[2] if ver != VER: raise ValueError("unsupported version") # Extract components off = 3 salt = blob[off:off + SALT_SZ] off += SALT_SZ orig_len = struct.unpack("<I", blob[off:off + 4])[0] off += 4 ct = blob[off:-TAG_SZ] tag = blob[-TAG_SZ:] # Derive keys and verify authentication enc_key, mac_key = derive_keys(key, salt) expected_tag = hmac.new(mac_key, blob[:off] + ct, hashlib.sha256).digest()[:TAG_SZ] if not hmac.compare_digest(expected_tag, tag): raise ValueError("authentication tag mismatch") # Decrypt and validate pt_padded = self.engine.decrypt(ct, enc_key) if orig_len > len(pt_padded): raise ValueError("invalid length in header") return pt_padded[:orig_len] 